function Calendar({ events }) {
  const { div, span, h3 } = tags;
  const [month, setMonth] = createSignal(new Date().getMonth());
  const [year, setYear] = createSignal(new Date().getFullYear());
  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const daysInMonth = new Date(year(), month() + 1, 0).getDate();
  const firstDay = new Date(year(), month(), 1).getDay();
  const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

  return Card({},
    Card.Header({},
      div({ class: css('_flex _aic _jcsb') },
        Button({ variant: 'ghost', size: 'sm', onclick: () => { if (month() === 0) { setMonth(11); setYear(year() - 1); } else setMonth(month() - 1); } }, icon('chevron-left', { size: '1em' })),
        h3({ class: css('_heading5') }, `${monthNames[month()]} ${year()}`),
        Button({ variant: 'ghost', size: 'sm', onclick: () => { if (month() === 11) { setMonth(0); setYear(year() + 1); } else setMonth(month() + 1); } }, icon('chevron-right', { size: '1em' }))
      )
    ),
    Card.Body({},
      div({ class: css('_grid _gc7 _gap1') },
        ...days.map(d => div({ class: css('_tc _textxs _fgmuted _py1') }, d)),
        ...Array(firstDay).fill(null).map(() => div({})),
        ...Array.from({ length: daysInMonth }, (_, i) => {
          const day = i + 1;
          const hasEvent = events?.some(e => e.day === day);
          return div({ class: css('_flex _col _aic _gap1 _p2 _r2 _cursor[pointer] _hover:bgmuted/10') },
            span({ class: css('_textsm') }, `${day}`),
            hasEvent ? div({ class: css('_w[6px] _h[6px] _rfull _bgprimary') }) : null
          );
        })
      )
    )
  );
}

