  const events = [
    { title: 'Deployed v2.4.1', time: '2 min ago', status: 'success' },
    { title: 'PR #142 merged', time: '15 min ago', status: 'success' },
    { title: 'Build failed', time: '1 hour ago', status: 'error' },
    { title: 'Tests passed', time: '2 hours ago', status: 'success' },
    { title: 'Branch created', time: '3 hours ago', status: null },
    { title: 'Issue #89 opened', time: '5 hours ago', status: null }
  ];
  const dotColor = s => s === 'success' ? '_bgsuccess' : s === 'error' ? '_bgerror' : '_bgmuted';

  return div({ class: css('_flex _col _gap1 _p2 _borderL _ml2') },
    ...events.map(e =>
      div({ class: css('_flex _aic _gap2 _py1 _relative') },
