function TimelineBranching() {
  const { div, span, code } = tags;
  const commits = [
    { hash: 'a1b2c3d', message: 'Merge feature/auth into main', author: 'Alice', branch: 'main', type: 'merge', mergedBranch: 'feature/auth' },
    { hash: 'e4f5g6h', message: 'Add OAuth2 provider support', author: 'Bob', branch: 'feature/auth', type: 'commit' },
    { hash: 'i7j8k9l', message: 'Implement token refresh logic', author: 'Bob', branch: 'feature/auth', type: 'commit' },
    { hash: 'm0n1o2p', message: 'Fix pagination offset bug', author: 'Carol', branch: 'main', type: 'commit' },
    { hash: 'q3r4s5t', message: 'Branch created from main', author: 'Bob', branch: 'feature/auth', type: 'branch' }
  ];
  const branchColor = b => b === 'main' ? '_bgprimary' : '_bgsuccess';

  return div({ class: css('_flex _col _gap0 _p4') },
    ...commits.map(c =>
      div({ class: css('_flex _gap3 _py3 _borderB') },
        div({ class: css('_flex _col _aic _w6') },
          div({ class: css(`_w[12px] _h[12px] _rfull ${branchColor(c.branch)} ${c.type === 'merge' ? '_b2 _bcborder' : ''}`) }),
          c.type !== 'branch' ? div({ class: css(`_w[2px] _flex1 ${branchColor(c.branch)}/30`) }) : null
        ),
        div({ class: css('_flex _col _gap1 _flex1') },
          div({ class: css('_flex _aic _gap2 _wrap') },
            span({ class: css('_textsm _bold') }, c.message),
            Badge({ variant: c.branch === 'main' ? 'default' : 'success', size: 'sm' }, c.branch),
            c.type === 'merge' ? Badge({ size: 'sm' }, icon('git-merge', { size: '0.75em' }), ` ${c.mergedBranch}`) : null
          ),
          div({ class: css('_flex _aic _gap2') },
            span({ class: css('_textxs _fgmuted') }, c.author),
            code({ class: css('_textxs _fgmuted _bgmuted/10 _px1 _r1') }, c.hash)
          )
        )
      )
    )
  );
}

