function TimelineMilestone() {
  const { div, span } = tags;
  const milestones = [
    { label: 'Planning', status: 'completed', date: 'Jan 2026' },
    { label: 'Design', status: 'completed', date: 'Feb 2026' },
    { label: 'Development', status: 'active', date: 'Mar 2026' },
    { label: 'Testing', status: 'upcoming', date: 'Apr 2026' },
    { label: 'Launch', status: 'upcoming', date: 'May 2026' }
  ];
  const nodeStyle = s => s === 'completed' ? '_bgprimary _fgonprimary' : s === 'active' ? '_b2 _bcprimary _bgbackground' : '_b2 _bcborder _bgbackground';
  const lineStyle = s => s === 'completed' ? '_bgprimary' : '_bgborder';

  return div({ class: css('_flex _aic _py4 _overflow[auto]') },
    ...milestones.flatMap((m, i) => [
      div({ class: css('_flex _col _aic _gap2 _shrink0 _w[120px]') },
        div({ class: css(`_flex _center _w8 _h8 _rfull ${nodeStyle(m.status)}`) },
          m.status === 'completed' ? icon('check', { size: '1em' }) : span({ class: css('_textsm _bold') }, `${i + 1}`)
        ),
        span({ class: css('_textsm _bold _tc') }, m.label),
        span({ class: css('_textxs _fgmuted') }, m.date),
        m.status === 'active' ? Badge({ variant: 'primary', size: 'sm' }, 'In Progress') : null
      ),
      i < milestones.length - 1 ? div({ class: css(`_h[2px] _w8 _shrink0 ${lineStyle(m.status)}`) }) : null
    ].filter(Boolean))
  );
}

